def validate_message(message_data):
    """Validate the structure and content of the deserialized message."""
    if not isinstance(message_data, dict):
        raise ValueError("Message data must be a JSON object (dict)")

    required_fields = ["task_type", "job_id", "payload"]
    for field in required_fields:
        if field not in message_data:
            raise ValueError(f"Missing required field: {field}")

    task_type = message_data["task_type"]
    if task_type not in TASK_HANDLERS:
        raise ValueError(f"Unknown task type: {task_type}. Allowed types: {list(TASK_HANDLERS.keys())}")

    job_id = message_data["job_id"]
    if not isinstance(job_id, str) or len(job_id) > 256:
        raise ValueError("job_id must be a string with max length 256")

    return True


@functions_framework.cloud_event
def process_batch_job(cloud_event):
    """
    Cloud Function triggered by Pub/Sub messages containing batch job definitions.

    Uses JSON deserialization (NOT pickle) for security.

    Expected message format (JSON):
    {
        "task_type": "data_transform",
        "job_id": "unique-job-id-123",
        "payload": {
            "input_data": [...],
            "operation": "normalize"
        },
        "metadata": {
            "submitted_by": "service-account@project.iam.gserviceaccount.com",
            "priority": "high"
        }
    }
    """
    try:
        # Extract the Pub/Sub message data
        pubsub_message = cloud_event.data.get("message", {})
        raw_data = pubsub_message.get("data")

        if not raw_data:
            logger.error("No data found in Pub/Sub message")
            return "No data", 400

        # Decode from base64 (Pub/Sub encodes messages in base64)
        decoded_data = base64.b64decode(raw_data)

        # --- SECURE DESERIALIZATION USING JSON ---
        # NEVER use pickle.loads() on data from Pub/Sub or any untrusted source.
        # pickle.loads() allows arbitrary code execution.
        message_data = json.loads(decoded_data)

        # Validate message structure and content
        validate_message(message_data)

        task_type = message_data["task_type"]
        job_id = message_data["job_id"]
        payload = message_data["payload"]
        metadata = message_data.get("metadata", {})

        logger.info(
            f"Processing batch job: job_id={job_id}, task_type={task_type}, "
            f"priority={metadata.get('priority', 'normal')}"
        )

        # Dispatch to the appropriate handler
        handler = TASK_HANDLERS[task_type]
        result = handler(payload)

        # Log completion
        result["job_id"] = job_id
        result["completed_at"] = datetime.utcnow().isoformat()
        logger.info(f"Job completed successfully: {json.dumps(result)}")

        return json.dumps(result), 200

    except json.JSONDecodeError as e:
        logger.error(f"Failed to decode JSON message: {e}")
        return f"Invalid JSON: {e}", 400

    except ValueError as e:
        logger.error(f"Message validation failed: {e}")
        return f"Validation error: {e}", 400

    except Exception as e:
        logger.error(f"Unexpected error processing batch job: {e}", exc_info=True)
        return f"Processing error: {e}", 500


