def example_publish_task():
    """Example showing how to publish a task (for reference, not part of the Cloud Function)."""
    from google.cloud import pubsub_v1

    publisher = pubsub_v1.PublisherClient()
    topic_path = publisher.topic_path("your-project-id", "batch-jobs-topic")

    task = {
        "task_type": "data_transform",
        "job_id": "job-20240101-001",
        "payload": {
            "input_data": [1, 2, 3, 4, 5],
            "operation": "normalize",
        },
        "metadata": {
            "submitted_by": "worker-service",
            "priority": "high",
        },
    }

    # Serialize as JSON - safe and interoperable
    message_bytes = json.dumps(task).encode("utf-8")
    future = publisher.publish(topic_path, data=message_bytes)
    print(f"Published message ID: {future.result()}")